     1→import { useRootStore } from '~/store';
     2→import { getPermissionApi, savePermissionApi } from '../api';
     3→import { PermissionStatus, type PermissionDocumentInput } from '../models';
     4→import { mapPermissionResponse } from '../repository';
     5→
     6→export async function checkHasRedeemed(accountId: string): Promise<boolean> {
     7→  const { rewardPermissionActions } = useRootStore.getState();
     8→
     9→  try {
    10→    rewardPermissionActions.setStatus(PermissionStatus.LOADING);
    11→
    12→    const response = await getPermissionApi({ accountNumber: accountId });
    13→
    14→    if (response.status >= 200 && response.status < 300 && response?.data) {
    15→      const permissionValue = mapPermissionResponse(response.data);
    16→      const redeemedAt =
    17→        permissionValue?.invoiceCashbackRedemption?.redeemedAtDate;
    18→      const hasRedeemed = Boolean(redeemedAt);
    19→
    20→      rewardPermissionActions.setHasRedeemed(hasRedeemed);
    21→      return hasRedeemed;
    22→    }
    23→
    24→    rewardPermissionActions.setStatus(PermissionStatus.ERROR);
    25→    return false;
    26→  } catch {
    27→    rewardPermissionActions.setStatus(PermissionStatus.ERROR);
    28→    return false;
    29→  }
    30→}
    31→
    32→export async function markAsRedeemed(accountId: string): Promise<boolean> {
    33→  const { rewardPermissionActions } = useRootStore.getState();
    34→
    35→  try {
    36→    const document: PermissionDocumentInput = {
    37→      codigoCliente: accountId,
    38→      status: 1,
    39→      value: JSON.stringify({
    40→        invoiceCashbackRedemption: {
    41→          redeemedAtDate: new Date().toISOString(),
    42→        },
    43→      }),
    44→    };
    45→
    46→    const response = await savePermissionApi(document);
    47→
    48→    if (response.status >= 200 && response.status < 300) {
    49→      rewardPermissionActions.setHasRedeemed(true);
    50→      return true;
    51→    }
    52→
    53→    return false;
    54→  } catch {
    55→    return false;
    56→  }
    57→}
